class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        List<Integer>[] red = new List[n];
        List<Integer>[] blue = new List[n];
        for (int i = 0; i < n; i++) {
            red[i] = new ArrayList<>();
            blue[i] = new ArrayList<>();
        }
        for (int[] edge : redEdges) {
            red[edge[0]].add(edge[1]);
        }
        for (int[] edge : blueEdges) {
            blue[edge[0]].add(edge[1]);
        }

        int[] res = new int[n];
        Arrays.fill(res, -1);
        res[0] = 0;

        Queue<int[]> q = new LinkedList<>();
        q.offer(new int[]{0, 0}); // node, color
        boolean[][] visited = new boolean[n][2];
        visited[0][0] = visited[0][1] = true;

        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int[] cur = q.poll();
                int node = cur[0], color = cur[1];
                int nextColor = color == 0 ? 1 : 0;
                List<Integer> nextEdges = color == 0 ? blue[node] : red[node];
                for (int next : nextEdges) {
                    if (!visited[next][nextColor]) {
                        visited[next][nextColor] = true;
                        if (res[next] == -1) {
                            res[next] = res[node] + 1;
                        }
                        q.offer(new int[]{next, nextColor});
                    }
                }
            }
        }
        return res;
    }
}
